import React from 'react';
import { CatalogCompanyTd } from '../CatalogCompanyColumn';
import { CatalogCodeWithReplaceBadge } from '../CatalogCodeReplaceListBadge';
import { useCatalogCodeReplaceForCode } from '../CatalogCodeReplaceContext';
import type { CatalogUiField } from '../../../types/catalogUiSchema';
import { formatMoneyVnd, formatQuantity } from '../../../utils/formatters';
import styles from '../../../styles/erpPage.module.css';

export interface CatalogSchemaCellProps {
  field: CatalogUiField;
  row: Record<string, unknown>;
  testIdPrefix?: string;
}

export const CatalogSchemaCell: React.FC<CatalogSchemaCellProps> = ({ field, row, testIdPrefix }) => {
  const value = row[field.key];
  const codeStr = value == null ? '' : String(value);
  const pending = useCatalogCodeReplaceForCode(
    field.control === 'CODE' || field.key === 'code' ? codeStr : '',
  );

  if (field.key === 'companyName') {
    return <CatalogCompanyTd label={value == null ? undefined : String(value)} />;
  }

  if (field.format === 'activeBadge' || (field.control === 'BOOL' && field.key === 'isActive')) {
    const active = !!value;
    return (
      <td>
        <span className={active ? styles.tagSuccess : styles.tagDefault}>
          {active ? 'Hoạt động' : 'Ngưng'}
        </span>
      </td>
    );
  }

  if (field.format === 'sharedScope' || field.key === 'scope') {
    const scope = String(value ?? '');
    const label = scope === 'Shared' ? 'Dùng chung' : scope === 'Company' ? 'Riêng đơn vị' : scope || '—';
    return <td>{label}</td>;
  }

  if (
    field.control === 'MONEY'
    || field.format === 'moneyVnd'
    || field.format === 'vnd'
  ) {
    return (
      <td className={styles.colRight}>
        {formatMoneyVnd(Number(value ?? 0))}
      </td>
    );
  }

  if (field.control === 'QTY' || field.format === 'quantity') {
    return (
      <td className={styles.colRight}>
        {value != null && value !== '' ? formatQuantity(Number(value)) : '—'}
      </td>
    );
  }

  if (field.control === 'CODE' || (field.key === 'code' && codeStr)) {
    const prefix = testIdPrefix ?? 'catalog';
    return (
      <td>
        {pending ? (
          <CatalogCodeWithReplaceBadge testIdPrefix={prefix} code={codeStr} pending={pending} />
        ) : (
          <code>{codeStr}</code>
        )}
      </td>
    );
  }

  if (field.control === 'BOOL') {
    return <td>{value ? 'Có' : 'Không'}</td>;
  }

  return <td>{value == null || value === '' ? '—' : String(value)}</td>;
};
